-- mig 344 — Phase C-2 bulk per-item service_intervals + procedures across 94 chassis.
-- Per (chassis, catalog_gen):
--   DELETE old v1 interval-header service rows (notes LIKE 'HaynesPro modelDetailMaintenance%')
